  function openMpSettings(){const f=$('#mp-settings-form');Object.entries(mp).forEach(([k,v])=>{if(!f.elements[k])return;if(f.elements[k].type==='checkbox')f.elements[k].checked=Boolean(v);else f.elements[k].value=v});$('#mp-settings-dialog').showModal()}
